/**
 * Parity test for the TS log-mel extractor against `transformers.WhisperFeatureExtractor`.
 *
 * The Python reference is generated once via fixtures/regenerate-mel-fixtures.py
 * (committed under fixtures/). This test compares Float32Array outputs
 * elementwise within 1e-3 — anything bigger and our encoder will diverge from
 * HF reference downstream.
 *
 * Fixture regeneration:
 *   python __tests__/fixtures/regenerate-mel-fixtures.py
 */
import { describe, expect, it } from 'vitest';
import { readFileSync } from 'node:fs';
import { join } from 'node:path';
import { extractMelSpectrogram, WHISPER_MEL } from '../src/mel-spectrogram';

const FIX = join(__dirname, 'fixtures');

function loadF32Bin(p: string): Float32Array {
  const buf = readFileSync(p);
  return new Float32Array(buf.buffer, buf.byteOffset, buf.byteLength / 4);
}

function loadWavMono16k(p: string): Float32Array {
  const buf = readFileSync(p);
  const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
  let pos = 12;
  let dataOffset = -1;
  let dataLen = 0;
  while (pos + 8 <= dv.byteLength) {
    const id = String.fromCharCode(
      dv.getUint8(pos),
      dv.getUint8(pos + 1),
      dv.getUint8(pos + 2),
      dv.getUint8(pos + 3),
    );
    const size = dv.getUint32(pos + 4, true);
    if (id === 'data') {
      dataOffset = pos + 8;
      dataLen = size;
      break;
    }
    pos += 8 + size + (size % 2);
  }
  if (dataOffset < 0) throw new Error(`missing data chunk in ${p}`);
  const samples = new Float32Array(dataLen / 2);
  for (let i = 0; i < samples.length; i++) {
    samples[i] = dv.getInt16(dataOffset + i * 2, true) / 32768;
  }
  return samples;
}

describe('extractMelSpectrogram', () => {
  it('matches WHISPER_MEL constants', () => {
    expect(WHISPER_MEL.sampleRate).toBe(16000);
    expect(WHISPER_MEL.nFft).toBe(400);
    expect(WHISPER_MEL.hopLength).toBe(160);
    expect(WHISPER_MEL.nMels).toBe(80);
    expect(WHISPER_MEL.nFrames).toBe(3000);
  });

  it('produces (n_mels, n_frames) shape', () => {
    const audio = new Float32Array(16000); // 1 second of silence
    const mel = extractMelSpectrogram(audio);
    expect(mel.length).toBe(80 * 3000);
  });

  it('matches HF Python reference within 1e-3 on a fixed wav', () => {
    let audio: Float32Array, ref: Float32Array;
    try {
      audio = loadWavMono16k(join(FIX, 'parity-input.wav'));
      ref = loadF32Bin(join(FIX, 'parity-mel-ref.f32'));
    } catch (e) {
      // Fixtures not generated yet — print regen instructions and skip.
      console.warn('mel parity fixture missing. regenerate with:');
      console.warn('  python __tests__/fixtures/regenerate-mel-fixtures.py');
      return;
    }
    const mel = extractMelSpectrogram(audio);
    expect(mel.length).toBe(ref.length);
    let maxAbs = 0;
    let argmax = 0;
    for (let i = 0; i < mel.length; i++) {
      expect(Number.isFinite(mel[i])).toBe(true);
      const d = Math.abs(mel[i] - ref[i]);
      if (d > maxAbs) { maxAbs = d; argmax = i; }
    }
    if (maxAbs > 1e-3) {
      const m = argmax % WHISPER_MEL.nFrames;
      const k = Math.floor(argmax / WHISPER_MEL.nFrames);
      console.error(`largest divergence: ${maxAbs.toFixed(6)} at mel=${k} frame=${m} (ours=${mel[argmax]} ref=${ref[argmax]})`);
    }
    expect(maxAbs).toBeLessThan(1e-3);
  });

  it('silence produces a flat mel near the floor', () => {
    const silence = new Float32Array(16000 * 5); // 5s silence
    const mel = extractMelSpectrogram(silence);
    // After log10(1e-10) → -10, clamp at max-8, normalize (+4)/4: silence should
    // hit exactly the same value at every (mel, frame) cell.
    const v0 = mel[0];
    expect(Number.isFinite(v0)).toBe(true);
    let maxDev = 0;
    for (let i = 0; i < mel.length; i++) {
      expect(Number.isFinite(mel[i])).toBe(true);
      const d = Math.abs(mel[i] - v0);
      if (d > maxDev) maxDev = d;
    }
    expect(maxDev).toBeLessThan(1e-6);
  });
});
